ExternalServiceRegistration.schema:
{
  "openapi": "3.0.0",
  "info": {
    "title": "Order Service",
    "version": "1.0.0",
    "description": "ERP Order Service API"
  },
  "paths": {
    "/orders": {
      "get": {
        "operationId": "getOrders",
        "summary": "Retrieve orders",
        "responses": {
          "200": {
            "description": "Successful response",
            "content": {
              "application/json": {
                "schema": {
                  "type": "array",
                  "items": {
                    "type": "object",
                    "properties": {
                      "orderId": { "type": "string" },
                      "status": { "type": "string" },
                      "total": { "type": "number" }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}
